1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single live cell (underpopulation)", () => {
10	    const liveCells: Cell[] = [[0, 0]];
11	    const result = nextGeneration(liveCells);
12	    expect(result).toEqual([]);
13	  });
14	  it("should kill two adjacent live cells (underpopulation)", () => {
15	    const liveCells: Cell[] = [[0, 0], [1, 0]];
16	    const result = nextGeneration(liveCells);
17	    expect(result).toEqual([]);
18	  });
19	  it("should keep a block pattern unchanged (still life)", () => {
20	    const liveCells: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
21	    const result = nextGeneration(liveCells);
22	    expect(result).toEqual(
23	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]])
24	    );
25	    expect(result).toHaveLength(4);
26	  });
27	  it("should oscillate a blinker from vertical to horizontal", () => {
28	    const liveCells: Cell[] = [[0, 0], [0, 1], [0, 2]];
29	    const result = nextGeneration(liveCells);
30	    expect(result).toEqual(
31	      expect.arrayContaining([[-1, 1], [0, 1], [1, 1]])
32	    );
33	    expect(result).toHaveLength(3);
34	  });
35	  it.todo("should handle cells with negative coordinates");
36	});
37

1	export type Cell = [number, number];
2	
3	const toKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const fromKey = (key: string): Cell => {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	};
9	
10	export function nextGeneration(liveCells: Cell[]): Cell[] {
11	  const alive = new Set(liveCells.map(([x, y]) => toKey(x, y)));
12	  const neighborCounts = new Map<string, number>();
13	
14	  for (const [x, y] of liveCells) {
15	    for (let dx = -1; dx <= 1; dx++) {
16	      for (let dy = -1; dy <= 1; dy++) {
17	        if (dx === 0 && dy === 0) continue;
18	        const key = toKey(x + dx, y + dy);
19	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
20	      }
21	    }
22	  }
23	
24	  const result: Cell[] = [];
25	  for (const [key, count] of neighborCounts) {
26	    if (count === 3 || (alive.has(key) && count === 2)) {
27	      result.push(fromKey(key));
28	    }
29	  }
30	
31	  return result;
32	}
